const sponsorsDataEl=document.getElementById("sponsors-data"),sponsorItems=document.querySelectorAll(".event-sponsors .cell"),sponsorModal=document.getElementById("sponsor-modal"),sponsorContent=document.getElementById("sponsor-content");if(sponsorsDataEl){const mapData=JSON.parse(sponsorsDataEl.textContent),{sponsors:sponsors}=mapData;sponsorItems.forEach((sponsorItem=>{sponsorItem.addEventListener("click",(()=>{const sponsor=sponsors.find((item=>item.id===sponsorItem.dataset.id));if(!sponsor)return;sponsorModal.heading=sponsor.company_name,sponsorContent.innerHTML=sponsor.content;const oldSubHeading=document.querySelector("#sponsor-modal .sub-heading");oldSubHeading&&oldSubHeading.remove();const subHeadingHtml=`\n               <div class="sub-heading">\n                    <div class="spacer x-small"></div>\n                    <div class="event-card-wrap">\n                         <div class="grid-x">\n                         <i class="icon-globals"></i>\n                         <span id="sponsor-email">${sponsor.link}</span>\n                         </div>\n                    </div>\n                    <div class="spacer"></div>\n                    <hr>\n               </div>\n               `;document.querySelector("#sponsor-modal .icon-close-1").insertAdjacentHTML("afterend",subHeadingHtml),sponsorModal.open()}))}))}